import React, { useState } from "react";
import InteractionForm from "./InteractionForm";
import ChatInterface from "./ChatInterface";
import InteractionList from "./InteractionList";

export default function LogInteractionScreen() {
  const [mode, setMode] = useState("form"); // 'form' | 'chat'

  return (
    <div className="app-shell">
      <div className="header">
        <h1>Log Interaction</h1>
        <p>Record your HCP engagement using a structured form or a conversational chat.</p>
      </div>

      <div className="mode-toggle">
        <button className={mode === "form" ? "active" : ""} onClick={() => setMode("form")}>
          📝 Form Mode
        </button>
        <button className={mode === "chat" ? "active" : ""} onClick={() => setMode("chat")}>
          💬 Chat Mode
        </button>
      </div>

      {mode === "form" ? <InteractionForm /> : <ChatInterface />}

      <InteractionList />
    </div>
  );
}
